import React from 'react';
import { useNavigate } from 'react-router-dom';

// ✅ setView prop-ah receive pannuroom
export default function Header({ setView }) {
  const navigate = useNavigate();
  const userName = localStorage.getItem("userName") || "User";

  const handleLogout = () => {
    localStorage.clear();
    navigate('/login');
  };

  // Function to handle navigation and view change
  const handleNavClick = (targetView) => {
    // Unga route marketplace-la illana anga navigate panniittu view-ah maathum
    navigate('/marketplace');
    if (setView) setView(targetView);
  };

  return (
    <header className="bg-slate-900 text-white py-4 px-8 flex justify-between items-center shadow-lg border-b border-slate-800">
      {/* Logo - Clicks back to Marketplace main view */}
      <div 
        className="flex items-center gap-2 cursor-pointer" 
        onClick={() => handleNavClick('marketplace')}
      >
        <span className="bg-red-600 p-2 rounded-lg text-xl">🚛</span>
        <h1 className="text-xl font-black italic tracking-tighter uppercase">
          Truck Board <span className="text-red-600">Pro</span>
        </h1>
      </div>

      <div className="flex items-center gap-6">
        <div className="hidden md:flex gap-6 text-xs font-bold uppercase tracking-widest text-slate-400">
          {/* ✅ OnClick events added to update view */}
          <span 
            className="hover:text-white cursor-pointer transition-colors"
            onClick={() => handleNavClick('marketplace')}
          >
            Find Loads
          </span>
          <span 
            className="hover:text-white cursor-pointer transition-colors"
            onClick={() => handleNavClick('marketplace')}
          >
            Post Truck
          </span>
        </div>
        
        <div className="flex items-center gap-3 bg-slate-800 px-4 py-2 rounded-2xl border border-slate-700">
          <div className="w-8 h-8 bg-red-600 rounded-full flex items-center justify-center font-black">
            {userName.charAt(0)}
          </div>
          <span className="text-sm font-bold">{userName}</span>
          <button 
            onClick={handleLogout}
            className="ml-2 text-[10px] bg-slate-700 hover:bg-red-600 px-2 py-1 rounded-md transition-all uppercase font-black"
          >
            Logout
          </button>
        </div>
      </div>
    </header>
  );
}
